		if (expression instanceof Join join) {
			return safeStructure(join.getLeftArg()) && safeStructure(join.getRightArg());
		}
		if (expression instanceof Union union) {
			return safeStructure(union.getLeftArg()) && safeStructure(union.getRightArg());
		}
		return false;
